def _sage_maker_model_deployment_to_nested(
    sage_maker_model_deployment: SageMakerModelDeployment,
) -> SageMakerModelDeploymentNested:
    """Convert flat SageMakerModelDeployment to nested format."""
    attrs = SageMakerModelDeploymentAttributes()
    _populate_sage_maker_model_deployment_attrs(attrs, sage_maker_model_deployment)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        sage_maker_model_deployment,
        _SAGE_MAKER_MODEL_DEPLOYMENT_REL_FIELDS,
        SageMakerModelDeploymentRelationshipAttributes,
    )
    return SageMakerModelDeploymentNested(
        guid=sage_maker_model_deployment.guid,
        type_name=sage_maker_model_deployment.type_name,
        status=sage_maker_model_deployment.status,
        version=sage_maker_model_deployment.version,
        create_time=sage_maker_model_deployment.create_time,
        update_time=sage_maker_model_deployment.update_time,
        created_by=sage_maker_model_deployment.created_by,
        updated_by=sage_maker_model_deployment.updated_by,
        classifications=sage_maker_model_deployment.classifications,
        classification_names=sage_maker_model_deployment.classification_names,
        meanings=sage_maker_model_deployment.meanings,
        labels=sage_maker_model_deployment.labels,
        business_attributes=sage_maker_model_deployment.business_attributes,
        custom_attributes=sage_maker_model_deployment.custom_attributes,
        pending_tasks=sage_maker_model_deployment.pending_tasks,
        proxy=sage_maker_model_deployment.proxy,
        is_incomplete=sage_maker_model_deployment.is_incomplete,
        provenance_type=sage_maker_model_deployment.provenance_type,
        home_id=sage_maker_model_deployment.home_id,
        depth=sage_maker_model_deployment.depth,
        immediate_upstream=sage_maker_model_deployment.immediate_upstream,
        immediate_downstream=sage_maker_model_deployment.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _sage_maker_model_deployment_from_nested(
    nested: SageMakerModelDeploymentNested,
) -> SageMakerModelDeployment:
    """Convert nested format to flat SageMakerModelDeployment."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SageMakerModelDeploymentAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAGE_MAKER_MODEL_DEPLOYMENT_REL_FIELDS,
        SageMakerModelDeploymentRelationshipAttributes,
    )
    return SageMakerModelDeployment(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_sage_maker_model_deployment_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sage_maker_model_deployment_to_nested_bytes(
    sage_maker_model_deployment: SageMakerModelDeployment, serde: Serde
) -> bytes:
    """Convert flat SageMakerModelDeployment to nested JSON bytes."""
    return serde.encode(
        _sage_maker_model_deployment_to_nested(sage_maker_model_deployment)
    )


def _sage_maker_model_deployment_from_nested_bytes(
    data: bytes, serde: Serde
) -> SageMakerModelDeployment:
    """Convert nested JSON bytes to flat SageMakerModelDeployment."""
    nested = serde.decode(data, SageMakerModelDeploymentNested)
    return _sage_maker_model_deployment_from_nested(nested)


